import React, { useContext, useEffect } from 'react';
import { AppContext } from '../context/AppContext';
import TaskCard from '../components/TaskCard';
import { getTasks } from '../services/api';

const Dashboard = () => {
    const { userName, tasks, setTasks, userId, navigate } = useContext(AppContext);

    useEffect(() => {
        if (userId) {
            getTasks(userId)
                .then(res => setTasks(res.data))
                .catch(err => console.error("Failed to fetch tasks", err));
        }
    }, [userId, setTasks]);

    const dateStr = new Date().toLocaleDateString('en-IN', {
        weekday: 'long',
        day: 'numeric',
        month: 'long',
        year: 'numeric'
    });

    const getGreeting = () => {
        const hr = new Date().getHours();
        if (hr < 12) return 'Good morning';
        if (hr < 18) return 'Good afternoon';
        return 'Good evening';
    };

    const doneCount = tasks.filter(t => t.status === 'done').length;
    const totalCount = tasks.length;
    const progressPct = totalCount ? (doneCount / totalCount) * 100 : 0;

    return (
        <div style={{
            flex: 1,
            backgroundColor: 'var(--warm-white)',
            display: 'flex',
            flexDirection: 'column',
            paddingTop: 'var(--sat)',
            overflow: 'hidden',
            animation: 'slideUp 0.3s cubic-bezier(0.22, 1, 0.36, 1)'
        }}>
            <div className="scroll-container" style={{ flex: 1, padding: '14px 20px 100px' }}>

                {/* Header section */}
                <div style={{ marginBottom: '24px' }}>
                    <h1 style={{
                        fontSize: 'clamp(24px, 6.5vw, 30px)',
                        color: 'var(--text-dark)',
                        marginBottom: '4px'
                    }}>
                        {getGreeting()}{userName ? `, ${userName}` : ''} 👋
                    </h1>
                    <div style={{ color: 'var(--text-light)', fontSize: '14px' }}>
                        {dateStr}
                    </div>
                </div>

                {/* Progress Card */}
                <div style={{
                    backgroundColor: 'var(--deep-teal)',
                    borderRadius: '20px',
                    padding: '24px',
                    color: '#fff',
                    position: 'relative',
                    overflow: 'hidden',
                    marginBottom: '32px',
                    boxShadow: 'var(--shadow-md)'
                }}>
                    {/* Decorative circle */}
                    <div style={{
                        position: 'absolute',
                        top: '-20px',
                        right: '-20px',
                        width: '150px',
                        height: '150px',
                        borderRadius: '50%',
                        backgroundColor: 'rgba(255,255,255,0.04)'
                    }} />

                    <div style={{
                        fontSize: '12px',
                        letterSpacing: '1px',
                        textTransform: 'uppercase',
                        color: 'rgba(255,255,255,0.6)',
                        marginBottom: '16px'
                    }}>
                        OVERALL PROGRESS
                    </div>

                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', marginBottom: '16px' }}>
                        <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '48px', lineHeight: 1 }}>
                            {doneCount}
                        </span>
                        <span style={{ fontSize: '18px', color: 'rgba(255,255,255,0.6)' }}>
                            / {totalCount} done
                        </span>
                    </div>

                    {/* Progress Bar */}
                    <div style={{
                        height: '6px',
                        backgroundColor: 'rgba(255,255,255,0.1)',
                        borderRadius: '3px',
                        marginBottom: '12px',
                        position: 'relative',
                        overflow: 'hidden'
                    }}>
                        <div style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            flex: 1,
                            height: '100%',
                            backgroundColor: 'var(--gold)',
                            borderRadius: '3px',
                            width: `${progressPct}%`,
                            transition: 'width 1s cubic-bezier(0.22, 1, 0.36, 1)'
                        }} />
                    </div>

                    <div style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)' }}>
                        {totalCount - doneCount} tasks remaining · est. 4–6 weeks
                    </div>
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                    <h3 style={{ fontSize: '18px', fontWeight: 600, color: 'var(--text-dark)', fontFamily: 'DM Sans, sans-serif' }}>
                        All Tasks
                    </h3>
                    <span style={{ fontSize: '14px', color: 'var(--text-mid)', fontWeight: 500 }}>
                        Filter ▾
                    </span>
                </div>

                {tasks.map((task, idx) => (
                    <TaskCard
                        key={idx}
                        {...task}
                        onClick={() => {
                            if (task.name.includes('SBI')) navigate('guidance');
                        }}
                    />
                ))}

                {!tasks.length && (
                    <div style={{ padding: '32px', textAlign: 'center', color: 'var(--text-light)' }}>
                        Loading customized task list...
                    </div>
                )}

            </div>
        </div>
    );
};

export default Dashboard;
